--- a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
@@ -5504,13 +5504,19 @@ bool SimplifyCFGOpt::simplifyUnreachable(UnreachableInst *UI) {
   return Changed;
 }

-static bool casesAreContiguous(SmallVectorImpl<ConstantInt *> &Cases) {
+static bool casesAreContiguous(SmallVectorImpl<ConstantInt *> &Cases,
+                               bool HasMinusOneAndZero = false) {
   assert(Cases.size() >= 1);

   array_pod_sort(Cases.begin(), Cases.end(), constantIntSortPredicate);
   for (size_t I = 1, E = Cases.size(); I != E; ++I) {
-    if (Cases[I - 1]->getValue() != Cases[I]->getValue() + 1)
-      return false;
+    if (Cases[I - 1]->getValue() + 1 != Cases[I]->getValue()) {
+      // Handle wrap-around: check if this is the wrap point where
+      // Cases[I-1] is max value and Cases[I] is 0.
+      // This handles cases like {-1, 0} which wrap around in unsigned.
+      if (I != E - 1 || !Cases[I]->isZero() || !Cases[I - 1]->isMinusOne())
+        return false;
+    }
   }
   return true;
 }
@@ -5545,6 +5551,95 @@ bool SimplifyCFGOpt::turnSwitchRangeIntoICmp(SwitchInst *SI,
                                              IRBuilder<> &Builder) {
   assert(SI->getNumCases() > 1 && "Degenerate switch?");

+  // Check if this is a switch on a ucmp/scmp result.
+  // ucmp/scmp returns -1, 0, or 1. If 2 of these 3 values go to one
+  // destination, we can convert to a direct icmp.
+  Value *Cond = SI->getCondition();
+  if (auto *II = dyn_cast<CmpIntrinsic>(Cond)) {
+    if (SI->getNumCases() == 2) {
+      // Collect which values go where
+      BasicBlock *BB1 = nullptr, *BB2 = nullptr;
+      ConstantInt *V1 = nullptr, *V2 = nullptr;
+      for (auto Case : SI->cases()) {
+        if (!V1) {
+          V1 = Case.getCaseValue();
+          BB1 = Case.getCaseSuccessor();
+        } else {
+          V2 = Case.getCaseValue();
+          BB2 = Case.getCaseSuccessor();
+        }
+      }
+      BasicBlock *DefaultBB = SI->getDefaultDest();
+      bool HasDefault =
+          !isa<UnreachableInst>(DefaultBB->getFirstNonPHIOrDbg());
+
+      if (V1 && V2 && BB1 == BB2 && HasDefault) {
+        // Both explicit cases go to same block, default goes elsewhere
+        // ucmp/scmp returns -1 (<), 0 (=), 1 (>)
+        // If V1,V2 = -1,0: check if >0 (a > b)
+        // If V1,V2 = 0,1: check if <0 (a < b)
+        APInt A1 = V1->getValue();
+        APInt A2 = V2->getValue();
+        bool IsSigned = II->isSigned();
+        Value *LHS = II->getLHS();
+        Value *RHS = II->getRHS();
+        ICmpInst::Predicate Pred;
+        BasicBlock *TrueBB, *FalseBB;
+
+        // Check which two values we have
+        if ((A1 == -1 && A2 == 0) || (A1 == 0 && A2 == -1)) {
+          // -1 and 0: a <= b goes to BB1, a > b goes to DefaultBB
+          Pred = IsSigned ? ICmpInst::ICMP_SGT : ICmpInst::ICMP_UGT;
+          TrueBB = DefaultBB;  // a > b
+          FalseBB = BB1;       // a <= b
+        } else if ((A1 == 0 && A2 == 1) || (A1 == 1 && A2 == 0)) {
+          // 0 and 1: a >= b goes to BB1, a < b goes to DefaultBB
+          Pred = IsSigned ? ICmpInst::ICMP_SLT : ICmpInst::ICMP_ULT;
+          TrueBB = DefaultBB;  // a < b
+          FalseBB = BB1;       // a >= b
+        } else if ((A1 == -1 && A2 == 1) || (A1 == 1 && A2 == -1)) {
+          // -1 and 1: a != b goes to BB1, a == b goes to DefaultBB
+          Pred = ICmpInst::ICMP_EQ;
+          TrueBB = DefaultBB;  // a == b
+          FalseBB = BB1;       // a != b
+        } else {
+          return false;
+        }
+
+        // Save default block before erasing SI
+        auto *UnreachableDefault = SI->getDefaultDest();
+        auto *BB = SI->getParent();
+        Builder.SetInsertPoint(SI);
+        Value *Cmp = Builder.CreateICmp(Pred, LHS, RHS, "switch.cmp");
+        BranchInst *NewBr = Builder.CreateCondBr(Cmp, TrueBB, FalseBB);
+
+        // Cleanup PHI nodes (similar to original code)
+        for (auto *Succ : {TrueBB, FalseBB}) {
+          for (auto BBI = Succ->begin(); isa<PHINode>(BBI); ++BBI) {
+            cast<PHINode>(BBI)->removeIncomingValue(BB);
+          }
+        }
+
+        // Drop the switch
+        SI->eraseFromParent();
+
+        // Erase the ucmp if it's now unused
+        if (II->use_empty())
+          II->eraseFromParent();
+
+        if (DTU) {
+          SmallVector<DominatorTree::UpdateType, 2> Updates;
+          Updates.push_back({DominatorTree::Insert, BB, TrueBB});
+          Updates.push_back({DominatorTree::Insert, BB, FalseBB});
+          if (!HasDefault)
+            Updates.push_back({DominatorTree::Delete, BB, UnreachableDefault});
+          DTU->applyUpdates(Updates);
+        }
+        return true;
+      }
+    }
+  }
+
   bool HasDefault =
       !isa<UnreachableInst>(SI->getDefaultDest()->getFirstNonPHIOrDbg());

