static bool casesAreContiguous(SmallVectorImpl<ConstantInt *> &Cases) {
  assert(Cases.size() >= 1);

  array_pod_sort(Cases.begin(), Cases.end(), constantIntSortPredicate);
  for (size_t I = 1, E = Cases.size(); I != E; ++I) {
    if (Cases[I - 1]->getValue() != Cases[I]->getValue() + 1)
      return false;
  }
  // Handle wrap-around: if the range spans the entire unsigned space
  // (e.g., [0, UINT_MAX]), check if they're adjacent due to overflow.
  // This handles cases like {-1, 0} which become [0, UINT_MAX] when sorted.
  if (Cases.size() > 1 && Cases.front()->isZero() &&
      Cases.back()->isMinusOne())
    return true;
  return true;
}
